function Gallery() {
  const categories = {
    Roofing: [
      "/assets/roof1.jpg",
      "/assets/roof2.jpg",
    ],
    Remodeling: [
      "/assets/roof3.jpg",
      "/assets/roof4.jpg",
    ],
    Decks: [
      "/assets/roof5.jpg",
      "/assets/roof6.jpg",
    ],
  };

  return (
    <div className="px-4 py-10 space-y-16">
      {Object.entries(categories).map(([category, images]) => (
        <div key={category}>
          <h3 className="text-2xl font-bold text-gray-800 mb-6 text-center">
            {category}
          </h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
            {images.map((src, idx) => (
              <img
                key={idx}
                src={src}
                alt={`${category} project ${idx + 1}`}
                loading="lazy"
                className="rounded-lg shadow-md hover:scale-105 transition-transform duration-300"
              />
            ))}
          </div>
        </div>
      ))}

      {/* CTA Section */}
      <div className="mt-20 text-center">
        <h3 className="text-3xl font-bold text-gray-900 mb-4">
          Ready to Start Your Project?
        </h3>
        <p className="text-lg text-gray-600 mb-6">
          Let James Salls Roofing & Remodeling bring your vision to life.
        </p>
        <a
          href="/contact"
          className="inline-block bg-black text-white px-6 py-3 rounded-md font-medium hover:bg-gray-800 transition"
        >
          Request a Free Quote
        </a>
      </div>
    </div>
  );
}

export default Gallery;
